mapper.select:
/* ProdSaleMonthStoreBensonMapper.getDivisionExcelDownloadUserIdChk */
SELECT  COUNT(*)
FROM    TB_HQ_NMCODE thn
WHERE   1=1
AND     thn.HQ_OFFICE_CD    = #{hqOfficeCd}
AND     thn.NMCODE_GRP_CD   = '168'
AND     thn.NMCODE_NM       = #{userId}

mapper.insert:
/* ProdSaleMonthStoreBensonMapper.getDivisionExcelDownloadSaveInsert */
INSERT INTO TB_CM_DOWNLOAD_LIMIT_CHECK
(
    ORGN_CD
,   SEQ
,   PROC_DT
,   USER_ID
,   DOWNLOAD_FG
,   RESRCE_CD
,   RESRCE_NM
,   DOWNLOAD_USE_FG
,   DOWNLOAD_START_DT
,   DOWNLOAD_FILE_COUNT
,   DOWNLOAD_EXPECTED_END_DT
,   REG_DT
,   REG_ID
,   MOD_DT
,   MOD_ID
,   DOWNLOAD_DT
)
VALUES
(
    #{orgnCd}
,   #{seq}
,   #{regDt}
,   #{userId}
,   #{downloadFg}
,   #{resrceCd}
,   #{resrceNm}
,   #{downloadUseFg}
,   #{regDt}
,   #{downloadFileCount}
,   #{downloadExpectedEndDt}
,   #{regDt}
,   #{regId}
,   #{modDt}
,   #{modId}
,   #{regDt}
)

mapper.select:
/* ProdSaleMonthStoreBensonMapper.getDownloadSeq */
SELECT  SQ_TB_CM_DOWNLOAD_LIMIT_CHECK.NEXTVAL AS SEQ
FROM    dual

mapper.update:
/* ProdSaleMonthStoreBensonMapper.getDivisionExcelDownloadSaveUpdate */
UPDATE  TB_CM_DOWNLOAD_LIMIT_CHECK
SET     DOWNLOAD_DT = #{modDt}
,       MOD_DT      = #{modDt}
,       MOD_ID      = #{modId}
WHERE   1=1
AND     ORGN_CD = #{orgnCd}
AND     SEQ     = #{seq}
